  ('optometrist-moex-02872', 'optometrist', 'optometrist-moex-107-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '王先生的眼鏡資訊為：右眼 -3.50 DS，前頂點屈光力 +6.00 D，中心厚度3 mm；左眼 -8.00 DS，前頂點 屈光力 +4.00 D，中心厚度2 mm；折射率皆為1.6，頂點距離為12 mm。有關眼鏡放大率的敘述，下列何 者錯誤？', '["左眼約為右眼1.06倍", "右眼眼鏡總放大率約為0.97倍", "右眼形狀放大率約為1.01倍", "左眼屈光放大率約為0.91倍"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "478f23e41698", "answer_pdf_sha1": "887bfdb0c709", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 48, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
